import { useLocation } from "react-router-dom";
import { useEffect, useState } from "react";
import "./styles/Books.css";

function LibrarianBooks() {
  const location = useLocation();

  // ✅ genre comes from login → dashboard → this page
  const genre = location.state?.genre;

  const [books, setBooks] = useState([]);

  /* 🚨 IMPORTANT: do NOT early return before hooks */

  // ✅ Load books for that genre (frontend demo data)
  useEffect(() => {
    if (!genre) return;

    // Demo data per genre (you can expand later)
    const demoData = {
      Fantasy: [
        {
          title: "Harry Potter",
          author: "J.K. Rowling",
          cover:
            "https://covers.openlibrary.org/b/id/7984916-L.jpg",
          status: "Available",
        },
        {
          title: "The Hobbit",
          author: "J.R.R. Tolkien",
          cover:
            "https://covers.openlibrary.org/b/id/6979861-L.jpg",
          status: "Not Available",
        },
      ],

      Literature: [
        {
          title: "Pride and Prejudice",
          author: "Jane Austen",
          cover:
            "https://covers.openlibrary.org/b/id/8091016-L.jpg",
          status: "Available",
        },
      ],
    };

    setBooks(demoData[genre] || []);
  }, [genre]);

  // ✅ TOGGLE STATUS
  const toggleStatus = (index) => {
    setBooks((prev) =>
      prev.map((book, i) =>
        i === index
          ? {
              ...book,
              status:
                book.status === "Available"
                  ? "Not Available"
                  : "Available",
            }
          : book
      )
    );
  };

  // ✅ REMOVE BOOK
  const removeBook = (index) => {
    setBooks((prev) => prev.filter((_, i) => i !== index));
  };

  // ✅ UI SAFETY
  if (!genre) {
    return (
      <h2 style={{ padding: "40px" }}>
        ❌ Genre not found. Please login again.
      </h2>
    );
  }

  return (
    <div className="books-page">
      <h1 className="books-title">Manage {genre} Books</h1>

      <div className="books-grid">
        {books.length === 0 ? (
          <p>No books found for this genre.</p>
        ) : (
          books.map((book, i) => (
            <div key={i} className="book-card">
              <img src={book.cover} alt={book.title} />

              <h3>{book.title}</h3>
              <p>{book.author}</p>

              <span
                className={`card-status ${
                  book.status === "Available"
                    ? "avail"
                    : "not-avail"
                }`}
              >
                {book.status}
              </span>

              <div
                style={{
                  marginTop: "14px",
                  display: "flex",
                  gap: "10px",
                  justifyContent: "center",
                }}
              >
                <button
                  className="borrow-btn"
                  onClick={() => toggleStatus(i)}
                >
                  🔁 Toggle Status
                </button>

                <button
                  className="return-btn"
                  onClick={() => removeBook(i)}
                >
                  ❌ Remove
                </button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}

export default LibrarianBooks;
